let DATA = loadData();
let adminLoggedIn = false;
let editCtx = null;
let deleteCtx = null;
const selectedCrew = [];
const selectedSupportItems = [];
const attachmentSelections = { sail:'', general:['','','','',''] };
const cosmeticSelections = { lantern:'' };
let selectedAmmo = 'round';
let ammoCollapsed = localStorage.getItem('wsb_ammo_collapsed')==='1';
let attachmentsCollapsed = localStorage.getItem('wsb_attachments_collapsed')==='1';
let cosmeticsCollapsed = localStorage.getItem('wsb_cosmetics_collapsed')==='1';
let crewCollapsed = localStorage.getItem('wsb_crew_collapsed')==='1';
let supportCollapsed = localStorage.getItem('wsb_support_collapsed')==='1';
function rateToRoman(n){const map={1:'I',2:'II',3:'III',4:'IV',5:'V',6:'VI',7:'VII'};return map[n]||String(n);}
function byId(id){return document.getElementById(id);}
function esc(value){return String(value==null?'':value).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;').replace(/'/g,'&#39;');}
function ensureMetaShape(store){if(!store.__meta||typeof store.__meta!=='object')store.__meta={};if(!Array.isArray(store.__meta.deletedDefaultCrewIds))store.__meta.deletedDefaultCrewIds=[];}function syncBuiltInCannons(store){ensureMetaShape(store);if(store.__meta.cannonCatalogVersion!==2){store.cannons=JSON.parse(JSON.stringify(DEFAULT_DATA.cannons));store.__meta.cannonCatalogVersion=2;}}function syncAttachmentCatalog(store){ensureMetaShape(store);if(store.__meta.attachmentCatalogVersion!==4){store.attachments=JSON.parse(JSON.stringify(DEFAULT_DATA.attachments));store.__meta.attachmentCatalogVersion=4;return;}for(const item of store.attachments){if(!item.slotType)item.slotType='general';}}function syncCosmeticCatalog(store){ensureMetaShape(store);if(store.__meta.cosmeticCatalogVersion!==3){store.cosmetics=JSON.parse(JSON.stringify(DEFAULT_DATA.cosmetics));store.__meta.cosmeticCatalogVersion=3;return;}for(const item of store.cosmetics){if(!item.slotType)item.slotType='lantern';}}
function isBuiltInCrewId(id){return DEFAULT_DATA.crew.some(item=>item.id===id);}
function mergeMissingDefaultCrew(store){ensureMetaShape(store);for(const crewItem of DEFAULT_DATA.crew){if(store.__meta.deletedDefaultCrewIds.includes(crewItem.id))continue;if(!store.crew.some(existing=>existing&&existing.id===crewItem.id)){store.crew.push(JSON.parse(JSON.stringify(crewItem)));}}}
function loadData(){try{const raw=localStorage.getItem('wsb_canvas_v3');if(!raw){const fresh=JSON.parse(JSON.stringify(DEFAULT_DATA));syncBuiltInCannons(fresh);syncAttachmentCatalog(fresh);syncCosmeticCatalog(fresh);return fresh;}const parsed=JSON.parse(raw);if(!parsed||typeof parsed!=='object'){const fresh=JSON.parse(JSON.stringify(DEFAULT_DATA));syncBuiltInCannons(fresh);return fresh;}if(!parsed.password)parsed.password=DEFAULT_DATA.password;for(const key of ['ships','cannons','attachments','cosmetics','armourTypes','ammo','crew','supportItems']){if(!Array.isArray(parsed[key]))parsed[key]=JSON.parse(JSON.stringify(DEFAULT_DATA[key]));}syncBuiltInCannons(parsed);syncAttachmentCatalog(parsed);syncCosmeticCatalog(parsed);mergeMissingDefaultCrew(parsed);return parsed;}catch(e){const fresh=JSON.parse(JSON.stringify(DEFAULT_DATA));syncBuiltInCannons(fresh);return fresh;}}
function saveData(){ensureMetaShape(DATA);DATA.__meta.cannonCatalogVersion=2;DATA.__meta.attachmentCatalogVersion=2;DATA.__meta.cosmeticCatalogVersion=3;localStorage.setItem('wsb_canvas_v3',JSON.stringify(DATA));}
function findById(list,id){return list.find(item=>item.id===id)||null;}
function findShip(id){return findById(DATA.ships,id);} function findCannon(id){return findById(DATA.cannons,id);} function findAmmo(id){return findById(DATA.ammo,id);} function findCrew(id){return findById(DATA.crew,id);}
function showToast(msg,isErr){const t=byId('toast');t.textContent=msg;t.className=isErr?'toast err show':'toast show';setTimeout(()=>{t.className=isErr?'toast err':'toast';},2200);}
function getActiveAttachmentIds(){const ids=[];if(attachmentSelections.sail)ids.push(attachmentSelections.sail);for(const id of attachmentSelections.general){if(id)ids.push(id);}return ids;} function getActiveCosmeticIds(){const ids=[];if(cosmeticSelections.lantern)ids.push(cosmeticSelections.lantern);return ids;}
function getCrewBonuses(){let dmgBonus=0,reloadBonus=0,speedBonus=0,maneuverBonus=0,penFlat=0;for(const crewId of selectedCrew){const c=findCrew(crewId);if(c){dmgBonus+=c.dmgBonus||0;reloadBonus+=c.reloadBonus||0;speedBonus+=c.speedBonus||0;maneuverBonus+=c.maneuverBonus||0;penFlat+=c.penFlat||0;}}return {dmgBonus,reloadBonus,speedBonus,maneuverBonus,penFlat};}function getSupportBonuses(){let dmgBonus=0,reloadBonus=0,speedBonus=0,maneuverBonus=0,penFlat=0;for(const supportId of selectedSupportItems){const item=findById(DATA.supportItems,supportId);if(item){dmgBonus+=item.dmgBonus||0;reloadBonus+=item.reloadBonus||0;speedBonus+=item.speedBonus||0;maneuverBonus+=item.maneuverBonus||0;penFlat+=item.penFlat||0;}}return {dmgBonus,reloadBonus,speedBonus,maneuverBonus,penFlat};}
function buildShipSelects(){const shipSel=byId('ship-select');const targetSel=byId('target-ship-select');if(!shipSel||!targetSel)return;const currentShip=shipSel.value;const currentTarget=targetSel.value;const sortedShips=DATA.ships.slice().sort((a,b)=>{if((a.rate||99)!==(b.rate||99))return (a.rate||99)-(b.rate||99);const typeCmp=String(a.shipType||'Unclassified').localeCompare(String(b.shipType||'Unclassified'));if(typeCmp!==0)return typeCmp;return String(a.name||'').localeCompare(String(b.name||''));});const groups=[];const groupMap=new Map();for(const ship of sortedShips){const typeLabel=ship.shipType||'Unclassified';const key=`${ship.rate}|${typeLabel}`;if(!groupMap.has(key)){const group={label:`Rate ${rateToRoman(ship.rate)} · ${typeLabel}`,ships:[]};groupMap.set(key,group);groups.push(group);}groupMap.get(key).ships.push(ship);}const fillSelect=(selectEl,placeholder,formatter)=>{selectEl.innerHTML='';const emptyOpt=document.createElement('option');emptyOpt.value='';emptyOpt.textContent=placeholder;selectEl.appendChild(emptyOpt);for(const group of groups){const optgroup=document.createElement('optgroup');optgroup.label=group.label;for(const ship of group.ships){const opt=document.createElement('option');opt.value=ship.id;opt.textContent=formatter(ship);optgroup.appendChild(opt);}selectEl.appendChild(optgroup);}};fillSelect(shipSel,'— Select a Ship —',ship=>`${ship.name} (${ship.slots} Cannon Slots)`);fillSelect(targetSel,'— Select Enemy Ship —',ship=>`${ship.name} (${ship.broadsideArmor} Armor · ${ship.slots} Slots)`);if(currentShip&&findShip(currentShip))shipSel.value=currentShip;if(currentTarget&&findShip(currentTarget))targetSel.value=currentTarget;}function renderShipOverview(ship){if(!ship)return '<div class="vessel-empty">Select a vessel to preview its class, broadside profile, and base handling stats.</div>';const badges=`<span class="rate-badge">Rate ${rateToRoman(ship.rate)}</span><span class="ship-type-badge stype-${esc(ship.shipType)}">${esc(ship.shipType)}</span>`;const stats=[['Cannon Slots',ship.slots,'gold'],['Broadside Armor',ship.broadsideArmor,'gold'],['Durability',ship.durability,'gold'],['Speed',ship.speed,'teal'],['Maneuverability',ship.maneuverability,'teal'],['Crew',ship.crew,'cream'],['Hold',ship.hold,'brass'],['Hull Dims',ship.hullDims||'—','cream']];const statHtml=stats.map(([k,v,tone])=>`<div class="vessel-stat-chip"><span class="vessel-stat-k">${esc(k)}</span><span class="vessel-stat-v ${tone||''}">${esc(v)}</span></div>`).join('');return `<div class="vessel-head"><div class="vessel-title-block"><div class="vessel-name">${esc(ship.name)}</div><div class="vessel-subtitle">${esc(ship.info||'Command profile ready for battery configuration.')}</div></div><div class="vessel-badge-row">${badges}</div></div><div class="vessel-divider"></div><div class="vessel-stat-grid">${statHtml}</div><div class="vessel-flavor">Weapon mount spread: ${esc(ship.heavyWeapons||'—')} · Displacement ${esc(ship.displacement||'—')} · Swivel guns ${ship.swivelGuns==null?'—':ship.swivelGuns}</div>`;}function renderTargetOverview(ship){if(!ship)return '<div class="vessel-empty">Select an enemy ship to compare its broadside armour, durability, speed, and crew profile.</div>';const meterWidth=Math.min(((ship.broadsideArmor||0)/12)*100,100);const badges=`<span class="rate-badge">Rate ${rateToRoman(ship.rate)}</span><span class="ship-type-badge stype-${esc(ship.shipType)}">${esc(ship.shipType)}</span>`;const stats=[['Durability',ship.durability,'gold'],['Speed',ship.speed,'teal'],['Crew',ship.crew,'cream'],['Cannon Slots',ship.slots,'gold']];const statHtml=stats.map(([k,v,tone])=>`<div class="vessel-stat-chip"><span class="vessel-stat-k">${esc(k)}</span><span class="vessel-stat-v ${tone||''}">${esc(v)}</span></div>`).join('');return `<div class="vessel-head"><div class="vessel-title-block"><div class="vessel-name">${esc(ship.name)}</div><div class="vessel-subtitle">Target profile locked. Effective damage will update live against this hull.</div></div><div class="vessel-badge-row">${badges}</div></div><div class="target-threat-row"><div><div class="target-threat-label">Broadside Armour</div><div class="target-armour-note">Each cannon hit loses this much damage before the volley total is calculated.</div></div><div class="target-threat-value">${esc(ship.broadsideArmor)}</div></div><div class="target-armour-meter"><div class="target-armour-fill" style="width:${meterWidth}%;"></div></div><div class="vessel-stat-grid">${statHtml}</div><div class="vessel-flavor">Hull: ${esc(ship.hullDims||'—')} · Displacement ${esc(ship.displacement||'—')} · Weapon spread ${esc(ship.heavyWeapons||'—')}</div>`;}
function romanToNumber(token){const map={I:1,II:2,III:3,IV:4,V:5,VI:6,VII:7};return map[String(token||'').trim()]||null;}function rankAllowsShip(rankStr,shipRate){if(!rankStr)return true;const values=String(rankStr).split('-').map(romanToNumber).filter(Boolean);if(!values.length)return true;const weakestAllowedRate=Math.max(...values);return shipRate<=weakestAllowedRate;}function getCannonsForPosition(shipRate,isBroadside,isStern){return DATA.cannons.filter(c=>{if(c.id==='none')return false;if(!rankAllowsShip(c.rank,shipRate))return false;if(isBroadside&&(String(c.category).includes('Bombard')||c.category==='Special'))return false;if(isStern&&c.category==='Special')return false;return true;});}function buildCannonOptions(shipRate,isBroadside,isStern){const orderedGroups=['Light Cannon','Medium Cannon','Heavy Cannon','Light Bombard','Medium Bombard','Heavy Bombard','Special'];const labelMap={'Light Cannon':'Light Cannons','Medium Cannon':'Medium Cannons','Heavy Cannon':'Heavy Cannons','Light Bombard':'Light Bombards','Medium Bombard':'Medium Bombards','Heavy Bombard':'Heavy Bombards','Special':'Special Weapons'};const list=getCannonsForPosition(shipRate,isBroadside,isStern);let html='<option value="none">— Empty —</option>';for(const category of orderedGroups){const items=list.filter(c=>c.category===category);if(!items.length)continue;html+=`<optgroup label="${labelMap[category]}">`;for(const c of items){const shotText=c.shots>1?` · ${c.shots} shots`:'';html+=`<option value="${esc(c.id)}">[${esc(c.rank)}] ${esc(c.name)} (${c.penetration} pen${shotText} · ${c.range}m)</option>`;}html+='</optgroup>';}return html;}function getDefaultCannonId(shipRate,isBroadside){const list=getCannonsForPosition(shipRate,isBroadside);if(!list.length)return 'none';const sorted=list.slice().sort((a,b)=>{if((b.penetration||0)!==(a.penetration||0))return (b.penetration||0)-(a.penetration||0);return (b.range||0)-(a.range||0);});return sorted[0].id;}function buildCannonSlots(ship){const wpParts=(ship.heavyWeapons||'').split('-').map(Number);const sternCount=wpParts.length===3?wpParts[0]:Math.min(2,Math.max(1,Math.floor(ship.slots*0.08)));const broadsideCount=wpParts.length===3?wpParts[1]:Math.ceil(ship.slots/2);const bowCount=wpParts.length===3?wpParts[2]:Math.min(2,Math.max(1,Math.floor(ship.slots*0.08)));const sideOptions=buildCannonOptions(ship.rate,true);const chaserOptions=buildCannonOptions(ship.rate,false);const sternOptions=buildCannonOptions(ship.rate,false,true);const defaultSide=getDefaultCannonId(ship.rate,true);const defaultChaser=getDefaultCannonId(ship.rate,false);function block(posId,label,count,selectedId,options,roleText,disabled){const c=findCannon(disabled?'none':selectedId);const armed=!disabled&&c&&c.dmg>0;return '<div class="cannon-position pos-'+posId+' '+(armed?'armed':'')+' '+(disabled?'pos-disabled':'')+'" id="pos-wrap-'+posId+'"><div class="pos-header"><span class="pos-title">'+label+'</span><span class="pos-count '+(armed?'has-cannon':'')+'" id="pos-count-'+posId+'">'+(disabled?'0 guns':count+' gun'+(count===1?'':'s'))+'</span></div><div class="pos-role">'+(disabled?'No guns available on this vessel':roleText)+'</div><div class="pos-select-wrap"><select id="pos-sel-'+posId+'" data-count="'+(disabled?0:count)+'" '+(disabled?'disabled':'')+' onchange="onPositionChange(\''+posId+'\')">'+(disabled?'<option value="none">\u2014 No guns \u2014</option>':options)+'</select></div><div class="pos-stats"><div class="pos-stat"><span class="pos-stat-lbl">Guns</span><span class="pos-stat-val">'+(disabled?'\u2014':count)+'</span></div><div class="pos-stat"><span class="pos-stat-lbl">Pen / gun</span><span class="pos-stat-val c-teal" id="pos-base-'+posId+'">'+(armed?c.penetration:'\u2014')+'</span></div><div class="pos-stat"><span class="pos-stat-lbl">Shots / gun</span><span class="pos-stat-val" id="pos-shots-'+posId+'">'+(armed?c.shots:'\u2014')+'</span></div><div class="pos-stat"><span class="pos-stat-lbl">Reload</span><span class="pos-stat-val" id="pos-reload-'+posId+'">'+(armed?c.reloadTime+'s':'\u2014')+'</span></div><div class="pos-stat"><span class="pos-stat-lbl">Range</span><span class="pos-stat-val" id="pos-range-'+posId+'">'+(armed?c.range+'m':'\u2014')+'</span></div><div class="pos-stat"><span class="pos-stat-lbl">Volley dmg</span><span class="pos-stat-val c-gold" id="pos-volley-'+posId+'">'+(armed?(c.dmg*count)+' dmg':'\u2014')+'</span></div></div></div>';}const bowDisabled=bowCount===0;const sternDisabled=sternCount===0;const sidesDisabled=broadsideCount===0;const totalGuns=broadsideCount*2+bowCount+sternCount;const armedTotal=(!sidesDisabled&&defaultSide!=='none'?broadsideCount*2:0)+(!bowDisabled&&defaultChaser!=='none'?bowCount:0)+(!sternDisabled&&defaultChaser!=='none'?sternCount:0);byId('cannon-slots-grid').innerHTML='<div class="ship-layout">'+block('bow','Bow Battery',bowCount,defaultChaser,chaserOptions,'Forward chase arc \u00b7 cannons, bombards &amp; specials',bowDisabled)+' '+block('port','Port Broadside',broadsideCount,defaultSide,sideOptions,'Port side firing line \u00b7 cannons only',sidesDisabled)+'<div class="broadside-ship-core"><div class="broadside-core-title">Deck Layout</div><div class="broadside-core-ship"></div><div class="broadside-core-note"><strong>Sides</strong> are your broadside batteries.<br><strong>Bow &amp; stern</strong> are chase mounts.</div></div>'+block('star','Starboard Broadside',broadsideCount,defaultSide,sideOptions,'Starboard firing line \u00b7 cannons only',sidesDisabled)+' '+block('stern','Stern Battery',sternCount,defaultChaser,sternOptions,'Rear chase arc \u00b7 cannons &amp; bombards only',sternDisabled)+'</div><div class="cannon-config-summary"><div class="cs-stat"><div class="cs-stat-lbl">Total Guns</div><div class="cs-stat-val">'+totalGuns+'</div></div><div class="cs-stat"><div class="cs-stat-lbl">Broadside</div><div class="cs-stat-val">'+(sidesDisabled?'\u2014':broadsideCount+'\u00d72')+'</div></div><div class="cs-stat"><div class="cs-stat-lbl">Chasers</div><div class="cs-stat-val">'+(bowCount+sternCount)+'</div></div><div class="cs-stat"><div class="cs-stat-lbl">Armed</div><div class="cs-stat-val" id="cs-armed">'+armedTotal+'</div></div></div>';if(!bowDisabled)byId('pos-sel-bow').value=defaultChaser;if(!sidesDisabled){byId('pos-sel-port').value=defaultSide;byId('pos-sel-star').value=defaultSide;}if(!sternDisabled)byId('pos-sel-stern').value=defaultChaser;}
function onShipChange(){const s=findShip(byId('ship-select').value);byId('ship-overview-card').innerHTML=renderShipOverview(s);if(!s){byId('cannon-slots-grid').innerHTML='<div style="color:var(--cream-dim);font-style:italic;font-size:0.85rem;">⚓ Select a vessel above to configure your broadside.</div>';byId('live-stats-wrap').innerHTML='<div class="live-placeholder">⚓ Select a vessel to see statistics.</div>';calculate();return;}buildCannonSlots(s);updateLiveStats();calculate();}
function onTargetShipChange(){const s=findShip(byId('target-ship-select').value);byId('target-overview-card').innerHTML=renderTargetOverview(s);calculate();}
function onPositionChange(posId){const sel=byId('pos-sel-'+posId);const count=Number(sel.dataset.count);const c=findCannon(sel.value);const armed=c&&c.dmg>0;byId('pos-base-'+posId).textContent=armed?c.penetration:'—';byId('pos-shots-'+posId).textContent=armed?c.shots:'—';byId('pos-reload-'+posId).textContent=armed?c.reloadTime+'s':'—';byId('pos-range-'+posId).textContent=armed?c.range+'m':'—';byId('pos-volley-'+posId).textContent=armed?(c.dmg*count)+' dmg':'—';const wrap=byId('pos-wrap-'+posId);const badge=byId('pos-count-'+posId);if(wrap)wrap.classList.toggle('armed',!!armed);if(badge)badge.classList.toggle('has-cannon',!!armed);let armedTotal=0;for(const slotId of ['port','star','bow','stern']){const slotSel=byId('pos-sel-'+slotId);if(!slotSel)continue;const slotCannon=findCannon(slotSel.value);if(slotCannon&&slotCannon.dmg>0)armedTotal+=Number(slotSel.dataset.count||0);}const armedEl=byId('cs-armed');if(armedEl)armedEl.textContent=String(armedTotal);updateLiveStats();calculate();}
function buildAmmo(){let html='';for(const a of DATA.ammo){let special='';if(a.special==='fire')special='<span class="ammo-special sp-fire">Incendiary</span>';if(a.special==='pierce')special='<span class="ammo-special sp-pierce">Piercing</span>';html+=`<div class="ammo-card ${a.id===selectedAmmo?'active':''}" data-id="${esc(a.id)}"><div><div class="ammo-card-title">${esc(a.name)}</div>${special}</div><div class="ammo-card-desc">${esc(a.desc)}</div><div class="ammo-stats"><div class="ammo-stat-row"><span class="ammo-stat-key">Damage to hull</span><span class="ammo-stat-val c-hull">${a.hullPct}%</span></div><div class="ammo-stat-row"><span class="ammo-stat-key">Damage to sails</span><span class="ammo-stat-val">${'☠'.repeat(a.sailsRating)+'<span style="opacity:0.25">'+'☠'.repeat(3-a.sailsRating)+'</span>'}</span></div><div class="ammo-stat-row"><span class="ammo-stat-key">Damage to crew</span><span class="ammo-stat-val">${'☠'.repeat(a.crewRating)+'<span style="opacity:0.25">'+'☠'.repeat(3-a.crewRating)+'</span>'}</span></div>${a.rangeModPct?'<div class="ammo-stat-row"><span class="ammo-stat-key" style="color:var(--red)">Firing range</span><span class="ammo-stat-val" style="color:var(--red)">'+(a.rangeModPct>0?'+':'')+a.rangeModPct+'%</span></div>':''}<div class="ammo-stat-row"><span class="ammo-stat-key">Weight</span><span class="ammo-stat-val c-weight">${a.weight}</span></div></div></div>`;}byId('ammo-grid').innerHTML=html;for(const card of document.querySelectorAll('.ammo-card')){card.onclick=function(){selectedAmmo=this.dataset.id;buildAmmo();updateLiveStats();calculate();};}}
function buildAttachments(){const sailItems=DATA.attachments.filter(a=>(a.slotType||'general')==='sail');const generalItems=DATA.attachments.filter(a=>(a.slotType||'general')!=='sail');if(attachmentSelections.sail&&!sailItems.some(a=>a.id===attachmentSelections.sail))attachmentSelections.sail='';attachmentSelections.general=attachmentSelections.general.map(id=>generalItems.some(a=>a.id===id)?id:'');const statHint=(item)=>{const parts=[];if(item.dmgBonus)parts.push((item.dmgBonus>0?'+':'')+Math.round(item.dmgBonus*100)+'% dmg');if(item.rateBonus)parts.push((item.rateBonus>0?'+':'')+Math.round(item.rateBonus*100)+'% reload');if(item.rangeFlatBonus)parts.push((item.rangeFlatBonus>0?'+':'')+item.rangeFlatBonus+'m range');if(item.speedBonus)parts.push((item.speedBonus>0?'+':'')+Math.round(item.speedBonus*100)+'% spd');if(item.maneuverBonus)parts.push((item.maneuverBonus>0?'+':'')+Math.round(item.maneuverBonus*100)+'% man');if(item.holdFlat)parts.push((item.holdFlat>0?'+':'')+item.holdFlat+' hold');if(item.holdPct)parts.push((item.holdPct>0?'+':'')+Math.round(item.holdPct*100)+'% hold');if(item.durabilityFlat)parts.push((item.durabilityFlat>0?'+':'')+item.durabilityFlat+' dur');if(item.durabilityPct)parts.push((item.durabilityPct>0?'+':'')+Math.round(item.durabilityPct*100)+'% dur');if(item.crewFlat)parts.push((item.crewFlat>0?'+':'')+item.crewFlat+' crew');if(item.armorFlat)parts.push((item.armorFlat>0?'+':'')+item.armorFlat+' armor');if(item.armorPct)parts.push((item.armorPct>0?'+':'')+Math.round(item.armorPct*100)+'% armor');if(item.penFlat)parts.push((item.penFlat>0?'+':'')+item.penFlat+' pen');return parts.length?' ('+parts.join(', ')+')':'';};const optionHtml=(items,selectedId)=>{const groups={};for(const item of items){const cat=item.category||'General';if(!groups[cat])groups[cat]=[];groups[cat].push(item);}let html='<option value="">— Empty —</option>';for(const [cat,list] of Object.entries(groups)){if(items.length>4)html+=`<optgroup label="${esc(cat)}">`;for(const item of list){html+=`<option value="${esc(item.id)}" ${item.id===selectedId?'selected':''}>${esc(item.name)}${esc(statHint(item))}</option>`;}if(items.length>4)html+='</optgroup>';}return html;};const previewHtml=(item,emptyText)=>{if(!item)return `<div class="loadout-slot-preview empty">${emptyText}</div>`;const bits=[];if(item.dmgBonus)bits.push(`<span class="stat">${item.dmgBonus>0?'+':''}${Math.round(item.dmgBonus*100)}% dmg</span>`);if(item.rateBonus)bits.push(`<span class="stat">${item.rateBonus>0?'+':''}${Math.round(item.rateBonus*100)}% reload</span>`);if(item.rangeFlatBonus)bits.push(`<span class="stat">${item.rangeFlatBonus>0?'+':''}${item.rangeFlatBonus}m range</span>`);if(item.speedBonus)bits.push(`<span class="stat">${item.speedBonus>0?'+':''}${Math.round(item.speedBonus*100)}% speed</span>`);if(item.maneuverBonus)bits.push(`<span class="stat">${item.maneuverBonus>0?'+':''}${Math.round(item.maneuverBonus*100)}% maneuver</span>`);if(item.holdFlat)bits.push(`<span class="stat">${item.holdFlat>0?'+':''}${item.holdFlat} hold</span>`);if(item.holdPct)bits.push(`<span class="stat">${item.holdPct>0?'+':''}${Math.round(item.holdPct*100)}% hold</span>`);if(item.durabilityFlat)bits.push(`<span class="stat">${item.durabilityFlat>0?'+':''}${item.durabilityFlat} durability</span>`);if(item.durabilityPct)bits.push(`<span class="stat">${item.durabilityPct>0?'+':''}${Math.round(item.durabilityPct*100)}% durability</span>`);if(item.crewFlat)bits.push(`<span class="stat">${item.crewFlat>0?'+':''}${item.crewFlat} crew</span>`);if(item.armorFlat)bits.push(`<span class="stat">${item.armorFlat>0?'+':''}${item.armorFlat} armor</span>`);if(item.armorPct)bits.push(`<span class="stat">${item.armorPct>0?'+':''}${Math.round(item.armorPct*100)}% armor</span>`);if(item.penFlat)bits.push(`<span class="stat">${item.penFlat>0?'+':''}${item.penFlat} pen → +${item.penFlat} dmg/gun</span>`);const statLine=bits.length?'<strong>'+bits.join(' · ')+'</strong><br>':'';return `<div class="loadout-slot-preview">${statLine}${esc(item.desc||'No notes yet.')}</div>`;};let generalCards='';for(let i=0;i<5;i+=1){const selectedId=attachmentSelections.general[i]||'';const selectedItem=findById(generalItems,selectedId);generalCards+=`<div class="loadout-slot-card"><div class="loadout-slot-label">Upgrade Slot ${i+1}</div><div class="select-wrap"><select class="js-general-attach-select" data-index="${i}">${optionHtml(generalItems,selectedId)}</select></div>${previewHtml(selectedItem,'Select a general upgrade for this slot.')}</div>`;}const selectedSail=findById(sailItems,attachmentSelections.sail);byId('attachments-grid').innerHTML=`<div class="loadout-slot-group"><div class="loadout-slot-head"><div class="loadout-slot-title">Sail Upgrade</div><div class="loadout-slot-subtitle">Each ship has 1 dedicated sail slot with 4 sail upgrade choices.</div></div><div class="loadout-slot-grid"><div class="loadout-slot-card"><div class="loadout-slot-label">Sail Slot</div><div class="select-wrap"><select id="attach-sail-select">${optionHtml(sailItems,attachmentSelections.sail)}</select></div>${previewHtml(selectedSail,'Select one sail upgrade.')}</div></div></div><div class="loadout-slot-group"><div class="loadout-slot-head"><div class="loadout-slot-title">General Upgrades</div><div class="loadout-slot-subtitle">Each ship also has 5 upgrade slots that can use any non-sail attachment.</div></div><div class="loadout-slot-grid">${generalCards}</div></div>`;const sailSelect=byId('attach-sail-select');if(sailSelect)sailSelect.onchange=function(){attachmentSelections.sail=this.value;buildAttachments();updateLiveStats();calculate();};for(const select of document.querySelectorAll('.js-general-attach-select')){select.onchange=function(){attachmentSelections.general[Number(this.dataset.index)]=this.value;buildAttachments();updateLiveStats();calculate();};}}
function buildCosmetics(){const lanternItems=DATA.cosmetics.filter(c=>(c.slotType||'lantern')==='lantern');if(cosmeticSelections.lantern&&!lanternItems.some(c=>c.id===cosmeticSelections.lantern))cosmeticSelections.lantern='';const cosStatHint=(item)=>{const parts=[];if(item.dmgBonus)parts.push((item.dmgBonus>0?'+':'')+Math.round(item.dmgBonus*100)+'% dmg');if(item.speedBonus)parts.push((item.speedBonus>0?'+':'')+Math.round(item.speedBonus*100)+'% spd');if(item.maneuverBonus)parts.push((item.maneuverBonus>0?'+':'')+Math.round(item.maneuverBonus*100)+'% man');if(item.holdPct)parts.push((item.holdPct>0?'+':'')+Math.round(item.holdPct*100)+'% hold');if(item.durabilityPct)parts.push((item.durabilityPct>0?'+':'')+Math.round(item.durabilityPct*100)+'% dur');if(item.armorPct)parts.push((item.armorPct>0?'+':'')+Math.round(item.armorPct*100)+'% armor');return parts.length?' ('+parts.join(', ')+')':'';};const optionHtml=(items,selectedId)=>'<option value="">— Empty —</option>'+items.map(item=>`<option value="${esc(item.id)}" ${item.id===selectedId?'selected':''}>${esc(item.name)}${esc(cosStatHint(item))}</option>`).join('');const previewHtml=(item,emptyText)=>{if(!item)return `<div class="loadout-slot-preview empty">${emptyText}</div>`;const bits=[];if(item.dmgBonus)bits.push(`<span class="stat">${item.dmgBonus>0?'+':''}${Math.round(item.dmgBonus*100)}% dmg</span>`);if(item.speedBonus)bits.push(`<span class="stat">${item.speedBonus>0?'+':''}${Math.round(item.speedBonus*100)}% speed</span>`);if(item.maneuverBonus)bits.push(`<span class="stat">${item.maneuverBonus>0?'+':''}${Math.round(item.maneuverBonus*100)}% maneuver</span>`);if(item.holdPct)bits.push(`<span class="stat">${item.holdPct>0?'+':''}${Math.round(item.holdPct*100)}% hold</span>`);if(item.durabilityPct)bits.push(`<span class="stat">${item.durabilityPct>0?'+':''}${Math.round(item.durabilityPct*100)}% durability</span>`);if(item.armorPct)bits.push(`<span class="stat">${item.armorPct>0?'+':''}${Math.round(item.armorPct*100)}% armor</span>`);const statLine=bits.length?'<strong>'+bits.join(' · ')+'</strong><br>':'';return `<div class="loadout-slot-preview">${statLine}${esc(item.desc||'No notes yet.')}</div>`;};const selectedLantern=findById(lanternItems,cosmeticSelections.lantern);byId('cosmetics-grid').innerHTML=`<div class="loadout-slot-group"><div class="loadout-slot-head"><div class="loadout-slot-title">Lantern Cosmetic</div><div class="loadout-slot-subtitle">Each ship has 1 dedicated large lantern slot — each lantern provides a unique stat bonus.</div></div><div class="loadout-slot-grid"><div class="loadout-slot-card"><div class="loadout-slot-label">Lantern Slot</div><div class="select-wrap"><select id="cosmetic-lantern-select">${optionHtml(lanternItems,cosmeticSelections.lantern)}</select></div>${previewHtml(selectedLantern,'Select a lantern cosmetic for this slot.')}</div></div></div>`;const lanternSelect=byId('cosmetic-lantern-select');if(lanternSelect)lanternSelect.onchange=function(){cosmeticSelections.lantern=this.value;buildCosmetics();updateLiveStats();calculate();};}
function buildCrew(){const groups=[{name:'Pirates',cls:'pirates',icon:'☠',salary:'10 gold/silver salary'},{name:'Sailors',cls:'sailors',icon:'⚓',salary:'30 gold/silver salary'},{name:'Military',cls:'military',icon:'⚔',salary:'30 gold/silver salary'},{name:'Adventurers',cls:'adventurers',icon:'🧭',salary:'25 gold/silver salary'}];let html='';for(const faction of groups){html+=`<div class="crew-faction-section"><div class="crew-faction-header ${faction.cls}"><span>${faction.icon} ${faction.name}</span><span class="crew-faction-salary">${faction.salary}</span></div><div class="crew-grid">`;for(const c of DATA.crew){if(c.faction===faction.name){const types=Array.isArray(c.types)?c.types:[];const tags=types.map(type=>`<span class="crew-type-badge ct-${esc(String(type).toLowerCase())}">${esc(type)}</span>`).join('');const active=selectedCrew.includes(c.id);const dmgText=c.dmgBonus?` · <span class="dmg-bonus">+${Math.round(c.dmgBonus*100)}% dmg</span>`:'';html+=`<div class="crew-card ${active?'active':''}" data-id="${esc(c.id)}"><div class="crew-card-name">${esc(c.name)}</div>${tags}<div class="crew-card-bonus">${esc(c.bonus)}${dmgText}</div></div>`;}}html+='</div></div>';}
  byId('crew-grid').innerHTML=html;
  for(const node of document.querySelectorAll('.crew-card')){node.onclick=function(){const id=this.dataset.id;const idx=selectedCrew.indexOf(id);if(idx>-1)selectedCrew.splice(idx,1);else{if(selectedCrew.length>=4){showToast('Maximum 4 crew members',true);return;}selectedCrew.push(id);}buildCrew();updateCrewSlots();updateLiveStats();calculate();};}
  updateCrewSlots();
}
function updateCrewSlots(){for(let i=0;i<4;i+=1){const slot=byId('crew-slot-'+i);if(selectedCrew[i]){const c=findCrew(selectedCrew[i]);slot.textContent=c?c.name:'Filled';slot.className='crew-slot filled';}else{slot.textContent='Empty';slot.className='crew-slot';}}byId('crew-count').textContent=String(selectedCrew.length);}const MAX_SUPPORT_ITEMS=3;const SUPPORT_GROUPS=[{name:'Repair & Durability',cls:'repair',note:'Sustain & plating'},{name:'Ship Enhancements',cls:'enhance',note:'Power & mobility'},{name:'Special Powders & Ammunition',cls:'powder',note:'Volley boosts'},{name:'Crew Items',cls:'crew',note:'Crew sustain'},{name:'Group Support Items',cls:'group',note:'Squadron utility'}];function updateSupportSlots(){for(let i=0;i<MAX_SUPPORT_ITEMS;i+=1){const slot=byId('support-slot-'+i);if(!slot)continue;if(selectedSupportItems[i]){const item=findById(DATA.supportItems,selectedSupportItems[i]);slot.textContent=item?item.name:'Filled';slot.className='support-slot filled';}else{slot.textContent='Empty';slot.className='support-slot';}}if(byId('support-count'))byId('support-count').textContent=String(selectedSupportItems.length);}function buildSupportItems(){while(selectedSupportItems.length>MAX_SUPPORT_ITEMS)selectedSupportItems.pop();const root=byId('support-grid');if(!root)return;let html='';for(const group of SUPPORT_GROUPS){html+=`<div class="support-group-section"><div class="support-group-header ${group.cls}"><span>${group.name}</span><span class="support-group-note">${group.note}</span></div><div class="support-items-grid">`;const items=DATA.supportItems.filter(item=>item.group===group.name);if(!items.length){html+='<div class="support-empty">No support items in this group yet.</div>';}for(const item of items){const tags=(Array.isArray(item.types)?item.types:[]).map(type=>`<span class="support-type-badge">${esc(type)}</span>`).join('');const active=selectedSupportItems.includes(item.id);const bits=[];if(item.dmgBonus)bits.push(`<span class="dmg-bonus">${item.dmgBonus>0?'+':''}${Math.round(item.dmgBonus*100)}% dmg</span>`);if(item.reloadBonus)bits.push(`<span class="reload-bonus">${item.reloadBonus>0?'+':''}${Math.round(item.reloadBonus*100)}% reload</span>`);if(item.speedBonus)bits.push(`<span class="speed-bonus">${item.speedBonus>0?'+':''}${Math.round(item.speedBonus*100)}% speed</span>`);if(item.maneuverBonus)bits.push(`<span class="maneuver-bonus">${item.maneuverBonus>0?'+':''}${Math.round(item.maneuverBonus*100)}% maneuver</span>`);const bonusLine=bits.length?bits.join(' · ')+' · ':'';html+=`<div class="support-item-card ${active?'active':''}" data-id="${esc(item.id)}"><div class="support-item-name">${esc(item.name)}</div>${tags}<div class="support-card-bonus">${bonusLine}${esc(item.bonus||'')}</div></div>`;}html+='</div></div>';}root.innerHTML=html;for(const node of document.querySelectorAll('.support-item-card')){node.onclick=function(){const id=this.dataset.id;const idx=selectedSupportItems.indexOf(id);if(idx>-1)selectedSupportItems.splice(idx,1);else{if(selectedSupportItems.length>=MAX_SUPPORT_ITEMS){showToast('Maximum 3 support items',true);return;}selectedSupportItems.push(id);}buildSupportItems();updateLiveStats();calculate();};}updateSupportSlots();}
