function getMultipliers(){let dmg=1,reloadMultiplier=1,rangeBonus=0,rangeFlatBonus=0,speedBonus=0,maneuverBonus=0,holdFlat=0,holdPct=0,durabilityFlat=0,durabilityPct=0,crewFlat=0,armorFlat=0,armorPct=0,penFlat=0;for(const id of getActiveAttachmentIds()){const a=findById(DATA.attachments,id);if(a){dmg+=a.dmgBonus||0;reloadMultiplier+=a.rateBonus||0;rangeBonus+=a.rangeBonus||0;rangeFlatBonus+=a.rangeFlatBonus||0;speedBonus+=a.speedBonus||0;maneuverBonus+=a.maneuverBonus||0;holdFlat+=a.holdFlat||0;holdPct+=a.holdPct||0;durabilityFlat+=a.durabilityFlat||0;durabilityPct+=a.durabilityPct||0;crewFlat+=a.crewFlat||0;armorFlat+=a.armorFlat||0;armorPct+=a.armorPct||0;penFlat+=a.penFlat||0;}}for(const id of getActiveCosmeticIds()){const c=findById(DATA.cosmetics,id);if(c){dmg+=c.dmgBonus||0;reloadMultiplier+=c.rateBonus||0;rangeBonus+=c.rangeBonus||0;speedBonus+=c.speedBonus||0;maneuverBonus+=c.maneuverBonus||0;holdFlat+=c.holdFlat||0;holdPct+=c.holdPct||0;durabilityFlat+=c.durabilityFlat||0;durabilityPct+=c.durabilityPct||0;armorFlat+=c.armorFlat||0;armorPct+=c.armorPct||0;}}const crew=getCrewBonuses();const support=getSupportBonuses();dmg+=crew.dmgBonus+support.dmgBonus;rangeBonus+=(crew.rangeBonus||0)+(support.rangeBonus||0);penFlat+=(crew.penFlat||0)+(support.penFlat||0);const totalReloadBonus=(reloadMultiplier-1)+crew.reloadBonus+support.reloadBonus;return {dmg,rate:1+totalReloadBonus,crew,support,totalReloadBonus,totalRangeBonus:rangeBonus,totalRangeFlatBonus:rangeFlatBonus,totalSpeedBonus:(crew.speedBonus||0)+(support.speedBonus||0)+speedBonus,totalManeuverBonus:(crew.maneuverBonus||0)+(support.maneuverBonus||0)+maneuverBonus,totalHoldFlat:holdFlat,totalHoldPct:holdPct,totalDurabilityFlat:durabilityFlat,totalDurabilityPct:durabilityPct,totalCrewFlat:crewFlat,totalArmorFlat:armorFlat,totalArmorPct:armorPct,totalPenFlat:penFlat};}
function updateLiveStats(){const ship=findShip(byId('ship-select').value);if(!ship){byId('live-stats-wrap').innerHTML='<div class="live-placeholder">⚓ Select a vessel to see a live command summary, hull profile, and modified combat projection.</div>';return;}const ammo=findAmmo(selectedAmmo)||DATA.ammo[0];const mult=getMultipliers();const speed=(ship.speed*(1+mult.totalSpeedBonus)).toFixed(1);const maneuver=Math.round(ship.maneuverability*(1+mult.totalManeuverBonus));const positions=[{id:'port',label:'Port Broadside'},{id:'star',label:'Starboard Broadside'},{id:'bow',label:'Bow Battery'},{id:'stern',label:'Stern Battery'}];let baseVolley=0;let modifiedVolley=0;let baseDpm=0;let modifiedDpm=0;let armedCount=0;let totalSlots=0;let slowestReload=0;const armedArcs=[];for(const pos of positions){const sel=byId('pos-sel-'+pos.id);if(!sel)continue;const count=Number(sel.dataset.count||0);const cannon=findCannon(sel.value)||findCannon('none');totalSlots+=count;if(cannon&&cannon.dmg>0){const baseArc=cannon.dmg*count;const reload=Math.max(1,cannon.reloadTime*(1-mult.totalReloadBonus));const modArc=((cannon.dmg+(mult.totalPenFlat||0))*mult.dmg*(ammo.hullPct/100))*count;armedCount+=count;baseVolley+=baseArc;modifiedVolley+=modArc;baseDpm+=(baseArc*60)/(cannon.reloadTime||1);modifiedDpm+=(modArc*60)/reload;slowestReload=Math.max(slowestReload,reload);armedArcs.push(pos.label+' · '+cannon.name);}}const activeAttachmentCount=getActiveAttachmentIds().length;const activeCosmeticCount=getActiveCosmeticIds().length;const activeCrewNames=selectedCrew.map(id=>findCrew(id)).filter(Boolean).map(item=>item.name);const activeSupportNames=selectedSupportItems.map(id=>findById(DATA.supportItems,id)).filter(Boolean).map(item=>item.name);const row=(key,val,cls)=>'<div class="live-stat-row"><span class="live-stat-key">'+key+'</span><span class="live-stat-dots"></span><span class="live-stat-val '+(cls||'c-cream')+'">'+val+'</span></div>';const section=(title,rows)=>'<div class="live-stat-section"><div class="live-stat-divider">'+title+'</div><div class="live-stat-list">'+rows+'</div></div>';const badges='<span class="rate-badge">Rate '+rateToRoman(ship.rate)+'</span><span class="ship-type-badge stype-'+esc(ship.shipType)+'">'+esc(ship.shipType)+'</span><span class="rate-badge">'+armedCount+'/'+totalSlots+' Guns Armed</span>';let baseCol='';const modDurability=Math.round((ship.durability+mult.totalDurabilityFlat)*(1+mult.totalDurabilityPct));const modHold=Math.round((ship.hold+mult.totalHoldFlat)*(1+mult.totalHoldPct));const modCrew=(ship.crew||0)+(mult.totalCrewFlat||0);const modArmor=Number(((ship.broadsideArmor||0)*(1+(mult.totalArmorPct||0))+(mult.totalArmorFlat||0)).toFixed(2));const durChanged=modDurability!==ship.durability;const holdChanged=modHold!==ship.hold;const crewChanged=modCrew!==ship.crew;const armorChanged=modArmor!==ship.broadsideArmor;baseCol+=section('Hull & Capacity',row('Durability',durChanged?ship.durability+' → '+modDurability:ship.durability,durChanged?'c-green':'c-gold')+row('Broadside Armor',armorChanged?ship.broadsideArmor+' → '+modArmor:ship.broadsideArmor,armorChanged?'c-green':'c-gold')+row('Crew',crewChanged?ship.crew+' → '+modCrew:ship.crew,crewChanged?'c-green':'c-cream')+row('Hold',holdChanged?ship.hold+' → '+modHold:ship.hold,holdChanged?'c-green':'c-brass')+row('Integrity',ship.integrity==null?'—':ship.integrity,'c-gold'));baseCol+=section('Mobility & Hull Form',row('Speed',ship.speed,'c-teal')+row('Maneuverability',ship.maneuverability,'c-teal')+row('Hull Dims',esc(ship.hullDims||'—'),'c-cream')+row('Displacement',esc(ship.displacement||'—'),'c-gold'));baseCol+=section('Battery Layout',row('Cannon Slots',ship.slots,'c-gold')+row('Weapons',esc(ship.heavyWeapons||'—'),'c-red')+row('Swivel Guns',ship.swivelGuns==null?'—':ship.swivelGuns,'c-cream')+row('Base Volley',armedCount?baseVolley.toFixed(1):'—',armedCount?'c-gold':'c-dim')+row('Base DPM',armedCount?baseDpm.toFixed(0):'—',armedCount?'c-teal':'c-dim'));let modifiedCol='';modifiedCol+=section('Combat Modifiers',row('Damage Multiplier','×'+mult.dmg.toFixed(2),Math.abs(mult.dmg-1)<0.001?'c-dim':'c-green')+row('Reload Multiplier','×'+mult.rate.toFixed(2),Math.abs(mult.rate-1)<0.001?'c-dim':'c-green')+row('Ammo Profile',esc(ammo.name)+' ('+ammo.hullPct+'%)','c-gold')+row('Attachments',activeAttachmentCount+'/6','c-green')+row('Cosmetics',activeCosmeticCount+'/2','c-green'));modifiedCol+=section('Adjusted Handling',row('Speed',speed,Number(speed)!==Number(ship.speed)?'c-green':'c-teal')+row('Maneuverability',maneuver,maneuver!==ship.maneuverability?'c-green':'c-teal')+row('Crew Loadout',activeCrewNames.length?activeCrewNames.length+'/4':'0/4',activeCrewNames.length?'c-green':'c-dim')+row('Support Loadout',activeSupportNames.length?activeSupportNames.length+'/'+MAX_SUPPORT_ITEMS:'0/'+MAX_SUPPORT_ITEMS,activeSupportNames.length?'c-green':'c-dim'));modifiedCol+=section('Battery Projection',row('Active Guns',armedCount+'/'+totalSlots,armedCount?'c-gold':'c-dim')+row('Modified Volley',armedCount?modifiedVolley.toFixed(1):'—',armedCount?'c-gold':'c-dim')+row('Modified DPM',armedCount?modifiedDpm.toFixed(0):'—',armedCount?'c-teal':'c-dim')+row('Slowest Reload',slowestReload?slowestReload.toFixed(1)+'s':'—',slowestReload?'c-cream':'c-dim'));const leftFoot='<div class="live-stat-foot"><strong>Ship profile:</strong> '+esc(ship.info||'No profile description entered yet.')+'</div>';const rightFoot='<div class="live-stat-foot"><strong>Battery arcs:</strong> '+(armedArcs.length?esc(armedArcs.join(' · ')):'No armed arcs selected yet.')+(activeCrewNames.length?' <br><strong>Crew:</strong> '+esc(activeCrewNames.join(', ')):'')+(activeSupportNames.length?' <br><strong>Support:</strong> '+esc(activeSupportNames.join(', ')):'')+'</div>';byId('live-stats-wrap').innerHTML='<div class="live-stats-shell"><div class="live-stats-hero"><div><div class="live-stats-kicker">Live Ship Profile</div><div class="live-stats-title">'+esc(ship.name)+'</div><div class="live-stats-note">Base hull metrics and your modified combat projection update instantly as you change loadout pieces, crew, and support.</div></div><div class="live-stats-badges">'+badges+'</div></div><div class="live-stats-ribbon"><div class="live-ribbon-card"><div class="live-ribbon-label">Base Output</div><div class="live-ribbon-value">'+(armedCount?baseVolley.toFixed(1)+' volley':'—')+'</div><div class="live-ribbon-note">'+(armedCount?baseDpm.toFixed(0)+' damage per minute before ammo and bonuses.':'No active guns loaded.')+'</div></div><div class="live-ribbon-card"><div class="live-ribbon-label">Combat Output</div><div class="live-ribbon-value">'+(armedCount?modifiedVolley.toFixed(1)+' volley':'—')+'</div><div class="live-ribbon-note">'+(armedCount?modifiedDpm.toFixed(0)+' damage per minute after modifiers.':'Select a battery to project live output.')+'</div></div><div class="live-ribbon-card"><div class="live-ribbon-label">Handling Profile</div><div class="live-ribbon-value">'+speed+' speed · '+maneuver+' man.</div><div class="live-ribbon-note">Adjusted handling after crew and support bonuses are applied.</div></div><div class="live-ribbon-card"><div class="live-ribbon-label">Loadout Status</div><div class="live-ribbon-value">'+activeAttachmentCount+'/6 att. · '+activeCosmeticCount+'/2 cos.</div><div class="live-ribbon-note">'+activeCrewNames.length+'/4 crew · '+activeSupportNames.length+'/'+MAX_SUPPORT_ITEMS+' support active.</div></div></div><div class="live-stats-panel"><div class="live-col"><div class="live-col-header base-header">⚓ Base Ship Overview</div><div class="live-col-body base-body">'+baseCol+leftFoot+'</div></div><div class="live-col"><div class="live-col-header bonus-header">✨ Modified Combat Profile</div><div class="live-col-body bonus-body">'+modifiedCol+rightFoot+'</div></div></div></div>';}function calculate(){const target=findShip(byId('target-ship-select').value);const ammo=findAmmo(selectedAmmo)||DATA.ammo[0]||{name:'Round Shots',hullPct:100};const mult=getMultipliers();const targetArmor=target?(target.broadsideArmor||0):0;const targetName=target?target.name:'No Armor Target';const ammoRangeMod=(ammo.rangeModPct||0)/100;const totalRangeMult=1+ammoRangeMod+(mult.totalRangeBonus||0);const totalRangeFlatBonus=mult.totalRangeFlatBonus||0;const rows=[];const positions=[{id:'port',label:'Port Broadside'},{id:'star',label:'Starboard Broadside'},{id:'bow',label:'Bow Chasers'},{id:'stern',label:'Stern Chasers'}];let totalVolley=0,totalDpm=0,totalGuns=0,armed=0;let slowestReload=0,shortestRange=Infinity,longestRange=0;for(const p of positions){const sel=byId('pos-sel-'+p.id);if(!sel)continue;const count=Number(sel.dataset.count||0);const cannon=findCannon(sel.value);totalGuns+=count;if(cannon&&cannon.dmg>0){armed+=count;const penBonus=mult.totalPenFlat||0;const modified=(cannon.dmg+penBonus)*mult.dmg*(ammo.hullPct/100);const effective=Math.max(0,modified-targetArmor);const reload=Math.max(1,cannon.reloadTime*(1-mult.totalReloadBonus));const baseRange=cannon.range;const effectiveRange=Math.round(baseRange*totalRangeMult)+totalRangeFlatBonus;const volley=effective*count;const dpm=(volley*60)/reload;slowestReload=Math.max(slowestReload,reload);if(effectiveRange<shortestRange)shortestRange=effectiveRange;if(effectiveRange>longestRange)longestRange=effectiveRange;totalVolley+=volley;totalDpm+=dpm;rows.push({label:p.label,cannon:cannon.name,count,base:cannon.dmg,penBonus,modified,effective,volley,reload,dpm,baseRange,effectiveRange});}}const avgPerGun=armed?(totalVolley/armed):0;const heroBadge=byId('results-hero-badge');if(heroBadge)heroBadge.textContent=armed?(armed+' Guns Online'):'Stand By';byId('stat-dps').textContent=totalVolley.toFixed(1);byId('stat-dpm').textContent=totalDpm.toFixed(0);byId('stat-burst').textContent=armed?avgPerGun.toFixed(1):'0';byId('stat-cannons').textContent=armed+'/'+totalGuns;byId('stat-dbonus').textContent='+'+Math.round((mult.dmg-1)*100)+'%';byId('stat-armour').textContent=targetArmor>0?('-'+targetArmor):'0';const activeCrewNames=selectedCrew.map(id=>findCrew(id)).filter(Boolean).map(c=>c.name);const activeSupportNames=selectedSupportItems.map(id=>findById(DATA.supportItems,id)).filter(Boolean).map(item=>item.name);const totalRangePct=Math.round(totalRangeMult*100-100);const rangePill=totalRangePct!==0?`<span class="bonus-pill ${totalRangePct>0?'pill-rate':'pill-armour'}">${totalRangePct>0?'+':''}${totalRangePct}% Range</span>`:'';const totalPenFlat2=mult.totalPenFlat||0;const penPill=totalPenFlat2?'<span class="bonus-pill pill-dmg">+'+totalPenFlat2+' Pen (flat +'+totalPenFlat2+' dmg/gun)</span>':'';let pills=`<span class="bonus-pill pill-dmg">${esc(ammo.name)} — Hull ${ammo.hullPct}%</span><span class="bonus-pill pill-dmg">Damage ×${mult.dmg.toFixed(2)}</span><span class="bonus-pill pill-rate">Rate ×${mult.rate.toFixed(2)}</span>${penPill}${rangePill}<span class="bonus-pill pill-armour">vs. ${esc(targetName)} Armor −${targetArmor}/shot</span>`;if(activeCrewNames.length)pills+=`<span class="bonus-pill pill-dmg">Crew ${esc(activeCrewNames.join(', '))}</span>`;if(activeSupportNames.length)pills+=`<span class="bonus-pill pill-rate">Support ${esc(activeSupportNames.join(', '))}</span>`;byId('bonus-pills').innerHTML=pills;const rangeNote=armed?(shortestRange===longestRange?('All active mounts effective at '+shortestRange+'m.'):('Active mounts span '+shortestRange+'m to '+longestRange+'m effective range.')):('No armed mounts to calculate range.');const rangeSrcParts=[];if(ammo.rangeModPct)rangeSrcParts.push('Ammo: '+(ammo.rangeModPct>0?'+':'')+ammo.rangeModPct+'%');if(mult.totalRangeBonus)rangeSrcParts.push('Loadout: '+(mult.totalRangeBonus>0?'+':'')+Math.round(mult.totalRangeBonus*100)+'%');const rangeSrcStr=rangeSrcParts.length?(' ('+rangeSrcParts.join(', ')+')'):' (no modifiers active)';const meta=byId('report-meta');if(meta){meta.innerHTML=`<div class="report-meta-grid"><div class="report-meta-card"><div class="report-meta-label">Engagement Target</div><div class="report-meta-value">${esc(targetName)}</div><div class="report-meta-note">${targetArmor>0?('Broadside armour removes '+targetArmor+' damage from each hit.'):('No armour reduction is being applied right now.')}</div></div><div class="report-meta-card"><div class="report-meta-label">Ammunition Profile</div><div class="report-meta-value">${esc(ammo.name)}</div><div class="report-meta-note">Hull damage modifier is ${ammo.hullPct}%${ammo.special?(' · '+esc(ammo.special)+' effect active'):''}.</div></div><div class="report-meta-card"><div class="report-meta-label">Battery Status</div><div class="report-meta-value">${armed}/${totalGuns} Guns Ready</div><div class="report-meta-note">${armed?('Average post-armour damage is '+avgPerGun.toFixed(1)+' per active cannon.'):('Select valid guns to bring the battery online.')}</div></div><div class="report-meta-card"><div class="report-meta-label">Broadside Cycle</div><div class="report-meta-value">${slowestReload?slowestReload.toFixed(1)+'s':'—'}</div><div class="report-meta-note">${slowestReload?('Slowest active mount sets the longest firing window.'):('No active reload cycle yet.')}</div></div><div class="report-meta-card"><div class="report-meta-label">Effective Range</div><div class="report-meta-value">${armed?(shortestRange===longestRange?shortestRange+'m':shortestRange+'m — '+longestRange+'m'):'—'}</div><div class="report-meta-note">${rangeNote+rangeSrcStr}</div></div><div class="report-meta-card"><div class="report-meta-label">Range Modifier</div><div class="report-meta-value" style="color:${totalRangePct<0?'var(--red)':totalRangePct>0?'var(--teal-light)':'inherit'}">${totalRangePct===0?'None':(totalRangePct>0?'+':'')+totalRangePct+'%'}</div><div class="report-meta-note">Combined ammo and loadout range adjustments applied to all active mounts.</div></div></div>`;}if(!rows.length){byId('breakdown-wrap').innerHTML='<div class="empty-result">⚓ No active cannons are loaded. Arm a battery to see a full per-position damage breakdown and sustained output view.</div>';return;}let table='<div class="breakdown-shell"><div class="breakdown-head"><div><div class="breakdown-title">Broadside Volley Breakdown</div><div class="breakdown-sub">Each row shows the live post-modifier, post-armour result for one firing arc, including effective range after all modifiers.</div></div><div class="results-hero-badge">'+armed+' Active Guns</div></div><div class="breakdown-scroll"><table class="breakdown-table"><thead><tr><th>Position</th><th>Cannon</th><th>Guns</th><th>Base Dmg</th><th>+Pen</th><th>Modified</th><th>Effective</th><th>Volley</th><th>Reload</th><th>DPM</th><th>Base Range</th><th>Eff. Range</th></tr></thead><tbody>';for(const r of rows){const rangeDelta=r.effectiveRange-r.baseRange;const rangeClass=rangeDelta<0?'td-armour':rangeDelta>0?'td-mod':'td-base';const rangeStr=rangeDelta!==0?`<span style="font-size:0.7em;opacity:0.7">(${rangeDelta>0?'+':''}${rangeDelta})</span>`:'';table+=`<tr><td class="td-cannon">${esc(r.label)}</td><td class="td-cannon">${esc(r.cannon)}</td><td class="td-base">${r.count}</td><td class="td-base">${r.base}</td><td class="td-base">${r.penBonus?'<span style="color:var(--teal-light)">+'+r.penBonus+'</span>':'—'}</td><td class="td-mod">${r.modified.toFixed(1)}</td><td class="td-eff">${r.effective.toFixed(1)}</td><td class="td-eff">${r.volley.toFixed(1)}</td><td class="td-base">${r.reload.toFixed(1)}s</td><td class="td-mod">${r.dpm.toFixed(0)}</td><td class="td-base">${r.baseRange}m</td><td class="${rangeClass}">${r.effectiveRange}m ${rangeStr}</td></tr>`;}table+=`</tbody><tfoot><tr><td colspan="9">Total Output</td><td class="td-mod">${totalDpm.toFixed(0)} DPM</td><td class="td-base">${armed?'—':'—'}</td><td class="td-eff">${armed?(shortestRange===longestRange?shortestRange+'m':shortestRange+'—'+longestRange+'m'):'—'}</td></tr></tfoot></table></div></div>`;byId('breakdown-wrap').innerHTML=table;}function openAdminOrLogin(){if(adminLoggedIn){byId('admin-overlay').classList.add('open');return;}byId('pw-modal-overlay').classList.add('open');}
function closePwModal(){byId('pw-modal-overlay').classList.remove('open');byId('pw-error').textContent='';byId('pw-input').value='';}
function tryLogin(){if(byId('pw-input').value===DATA.password){adminLoggedIn=true;byId('admin-lock-icon').textContent='🔓';byId('admin-btn-label').textContent='Admin Panel';closePwModal();byId('admin-overlay').classList.add('open');}else{byId('pw-error').textContent='Incorrect password.';}}
function closeAdmin(){byId('admin-overlay').classList.remove('open');}
function switchTab(name,btn){for(const tab of document.querySelectorAll('.adm-tab'))tab.classList.remove('active');for(const content of document.querySelectorAll('.adm-tab-content'))content.classList.remove('active');btn.classList.add('active');byId('tab-'+name).classList.add('active');}
function buildAdminTables(){let html='';for(let i=0;i<DATA.ships.length;i+=1){const s=DATA.ships[i];html+=`<tr><td class="td-name">${esc(s.name)}</td><td><span class="ship-type-badge stype-${esc(s.shipType)}" style="font-size:0.62rem;padding:0.1rem 0.45rem;margin:0;">${esc(s.shipType)}</span></td><td class="td-num">${s.slots}</td><td class="td-num">${s.durability}</td><td class="td-pos">${s.speed}</td><td class="td-pos">${s.maneuverability}</td><td class="td-num">${s.broadsideArmor}</td><td class="td-brass">${s.hold}</td><td>${s.crew}</td><td>${esc(s.hullDims)}</td><td>${esc(s.displacement)}</td><td>${esc(s.heavyWeapons)}</td><td>${s.swivelGuns==null?'—':s.swivelGuns}</td><td>${s.integrity==null?'—':s.integrity}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="ship" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="ship" data-index="${i}" data-name="${esc(s.name)}">✕ Del</button></div></td></tr>`;}byId('adm-ships-tbody').innerHTML=html;html='';for(let i=0;i<DATA.cannons.length;i+=1){const c=DATA.cannons[i];html+=`<tr><td>${esc(c.category||'—')}</td><td class="td-name">${esc(c.name)}</td><td class="td-num">${esc(c.rank||'—')}</td><td class="td-num">${c.dmg}</td><td class="td-num">${c.penetration}</td><td class="td-num">${c.shots}</td><td class="td-pos">${c.reloadTime?c.reloadTime+'s':'—'}</td><td class="td-pos">${c.range?c.range+'m':'—'}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="cannon" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="cannon" data-index="${i}" data-name="${esc(c.name)}">✕ Del</button></div></td></tr>`;}byId('adm-cannons-tbody').innerHTML=html;html='';for(let i=0;i<DATA.attachments.length;i+=1){const a=DATA.attachments[i];html+=`<tr><td>${esc(a.slotType||'general')}</td><td class="td-name">${esc(a.name)}</td><td class="td-pos">${a.dmgBonus>=0?'+':''}${Math.round(a.dmgBonus*100)}%</td><td class="td-pos">${a.rateBonus>=0?'+':''}${Math.round(a.rateBonus*100)}%</td><td>${esc(a.desc)}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="attachment" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="attachment" data-index="${i}" data-name="${esc(a.name)}">✕ Del</button></div></td></tr>`;}byId('adm-attachments-tbody').innerHTML=html;html='';for(let i=0;i<DATA.cosmetics.length;i+=1){const c=DATA.cosmetics[i];html+=`<tr><td>${esc(c.slotType||'torch')}</td><td class="td-name">${esc(c.name)}</td><td class="td-pos">${c.dmgBonus>=0?'+':''}${Math.round(c.dmgBonus*100)}%</td><td class="td-pos">${c.rateBonus>=0?'+':''}${Math.round(c.rateBonus*100)}%</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="cosmetic" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="cosmetic" data-index="${i}" data-name="${esc(c.name)}">✕ Del</button></div></td></tr>`;}byId('adm-cosmetics-tbody').innerHTML=html;html='';for(let i=0;i<DATA.ammo.length;i+=1){const a=DATA.ammo[i];html+=`<tr><td class="td-name">${esc(a.name)}</td><td class="td-num">${a.hullPct}%</td><td>${a.sailsRating}</td><td>${a.crewRating}</td><td>${a.weight}</td><td>${esc(a.special||'—')}</td><td>${esc(a.desc)}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="ammo" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="ammo" data-index="${i}" data-name="${esc(a.name)}">✕ Del</button></div></td></tr>`;}byId('adm-ammo-tbody').innerHTML=html;html='';for(let i=0;i<DATA.crew.length;i+=1){const c=DATA.crew[i];const types=Array.isArray(c.types)&&c.types.length?c.types.join(', '):'—';const dmg=c.dmgBonus?`+${Math.round(c.dmgBonus*100)}%`:'—';const reload=c.reloadBonus?`+${Math.round(c.reloadBonus*100)}%`:'—';const speed=c.speedBonus?`+${Math.round(c.speedBonus*100)}%`:'—';const maneuver=c.maneuverBonus?`+${Math.round(c.maneuverBonus*100)}%`:'—';html+=`<tr><td>${esc(c.faction||'—')}</td><td class="td-name">${esc(c.name)}</td><td>${esc(types)}</td><td class="td-pos">${dmg}</td><td class="td-pos">${reload}</td><td class="td-pos">${speed}</td><td class="td-pos">${maneuver}</td><td style="max-width:260px;">${esc(c.bonus||'')}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="crew" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="crew" data-index="${i}" data-name="${esc(c.name)}">✕ Del</button></div></td></tr>`;}byId('adm-crew-tbody').innerHTML=html;html='';for(let i=0;i<DATA.supportItems.length;i+=1){const s=DATA.supportItems[i];const types=Array.isArray(s.types)&&s.types.length?s.types.join(', '):'—';const dmg=s.dmgBonus?`+${Math.round(s.dmgBonus*100)}%`:'—';const reload=s.reloadBonus?`+${Math.round(s.reloadBonus*100)}%`:'—';const speed=s.speedBonus?`+${Math.round(s.speedBonus*100)}%`:'—';const maneuver=s.maneuverBonus?`+${Math.round(s.maneuverBonus*100)}%`:'—';html+=`<tr><td>${esc(s.group||'—')}</td><td class="td-name">${esc(s.name)}</td><td>${esc(types)}</td><td class="td-pos">${dmg}</td><td class="td-pos">${reload}</td><td class="td-pos">${speed}</td><td class="td-pos">${maneuver}</td><td style="max-width:260px;">${esc(s.bonus||'')}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="supportitem" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="supportitem" data-index="${i}" data-name="${esc(s.name)}">✕ Del</button></div></td></tr>`;}byId('adm-support-tbody').innerHTML=html;html='';for(let i=0;i<DATA.armourTypes.length;i+=1){const a=DATA.armourTypes[i];html+=`<tr><td class="td-name">${esc(a.name)}</td><td class="td-num">${a.value}</td><td><div class="row-actions"><button class="btn-edit js-edit" data-type="armourtype" data-index="${i}">✏ Edit</button><button class="btn-del js-del" data-type="armourtype" data-index="${i}" data-name="${esc(a.name)}">✕ Del</button></div></td></tr>`;}byId('adm-armour-tbody').innerHTML=html;bindAdminButtons();}function bindAdminButtons(){for(const btn of document.querySelectorAll('.js-edit'))btn.onclick=function(){openEditModal(this.dataset.type,Number(this.dataset.index));};for(const btn of document.querySelectorAll('.js-del'))btn.onclick=function(){openDeleteConfirm(this.dataset.type,Number(this.dataset.index),this.dataset.name);};}
function getArrayForType(type){if(type==='ship')return DATA.ships;if(type==='cannon')return DATA.cannons;if(type==='attachment')return DATA.attachments;if(type==='cosmetic')return DATA.cosmetics;if(type==='ammo')return DATA.ammo;if(type==='crew')return DATA.crew;if(type==='supportitem')return DATA.supportItems;if(type==='armourtype')return DATA.armourTypes;return null;}
function templateForType(type){if(type==='ship')return { id:'new_ship', name:'New Ship', shipType:'Fast', rate:5, slots:10, durability:1000, speed:8, maneuverability:80, broadsideArmor:2, hold:10000, crew:80, hullDims:'30x5', displacement:'1200t', heavyWeapons:'0-10-0', swivelGuns:4, integrity:5, info:'' };if(type==='cannon')return { id:'new_cannon', category:'Medium Cannon', rank:'I', dmg:20, penetration:20, shots:1, reloadTime:22, range:90, maxAngle:16, scatter:3.6, name:'New Cannon', desc:'Describe this cannon.' };if(type==='attachment')return { id:'new_attachment', slotType:'general', name:'New Attachment', desc:'Describe this attachment.', dmgBonus:0, rateBonus:0 };if(type==='cosmetic')return { id:'new_cosmetic', slotType:'lantern', name:'New Cosmetic', desc:'Describe this cosmetic.', dmgBonus:0, rateBonus:0, speedBonus:0, maneuverBonus:0, holdFlat:0, holdPct:0, durabilityFlat:0, durabilityPct:0, armorFlat:0, armorPct:0 };if(type==='ammo')return { id:'new_ammo', name:'New Ammo', desc:'Describe this ammo.', hullPct:100, sailsRating:1, crewRating:1, weight:1, special:'' };if(type==='crew')return { id:'new_crew', faction:'Pirates', types:['Combat'], name:'New Crew Member', bonus:'Describe this crew bonus.', dmgBonus:0, reloadBonus:0, speedBonus:0, maneuverBonus:0 };if(type==='supportitem')return { id:'new_support_item', group:'Ship Enhancements', types:['Damage'], name:'New Support Item', bonus:'Describe this support item.', dmgBonus:0, reloadBonus:0, speedBonus:0, maneuverBonus:0 };if(type==='armourtype')return { id:'new_armour', name:'New Armour Type', value:10 };return { id:'new_item', name:'New Item' };}
function getFieldDefs(type){if(type==='ship')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. 12 Apostolov',hint:'Display name in the calculator'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. apostolov',hint:'Lowercase, no spaces'},{key:'shipType',label:'Ship Type',kind:'select',options:['Fast','Combat','Transport','Heavy','Siege','Imperial']},{key:'slots',label:'Cannon Slots',kind:'number',placeholder:'24',hint:'Number of cannon slots'},{key:'durability',label:'Durability',kind:'number',placeholder:'4400',hint:'Max hull hit points'},{key:'speed',label:'Speed',kind:'number',placeholder:'6.2',step:'any',hint:'Sailing speed stat'},{key:'maneuverability',label:'Maneuverability',kind:'number',placeholder:'49',hint:'Turning/handling stat'},{key:'broadsideArmor',label:'Broadside Armor',kind:'number',placeholder:'10',step:'any',hint:'Side armour rating'},{key:'hold',label:'Hold',kind:'number',placeholder:'36000',hint:'Cargo hold capacity'},{key:'crew',label:'Crew',kind:'number',placeholder:'220',hint:'Crew complement'},{key:'hullDims',label:'Hull Dims (L×H)',kind:'text',placeholder:'66x11',hint:'e.g. 66x11'},{key:'displacement',label:'Displacement',kind:'text',placeholder:'4500t',hint:'e.g. 4500t'},{key:'heavyWeapons',label:'Weapons (Type Min-Max-Cur)',kind:'text',placeholder:'0-59-0',hint:'e.g. Heavy 0-59-0 / Medium 0-18-2 / Light 0-6-0'},{key:'swivelGuns',label:'Swivel Guns',kind:'number',placeholder:'10',nullable:true,hint:'Number of swivel guns'},{key:'integrity',label:'Integrity',kind:'number',placeholder:'7',nullable:true,hint:'Structural integrity rating'},{key:'info',label:'Description',kind:'textarea',full:true,placeholder:'Flavour text shown in the calculator',hint:''}];if(type==='cannon')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. 48-lb. Giant'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. hc_giant',hint:'Lowercase, underscores ok'},{key:'category',label:'Category',kind:'select',options:['None','Light Cannon','Medium Cannon','Heavy Cannon','Light Bombard','Medium Bombard','Heavy Bombard','Special']},{key:'rank',label:'Rank',kind:'text',placeholder:'e.g. I'},{key:'dmg',label:'Base Damage',kind:'number',placeholder:'48'},{key:'penetration',label:'Penetration',kind:'number',placeholder:'48',step:'any'},{key:'shots',label:'Shots',kind:'number',placeholder:'1'},{key:'reloadTime',label:'Reload Time',kind:'number',placeholder:'30',step:'any'},{key:'range',label:'Range',kind:'number',placeholder:'90',step:'any'},{key:'maxAngle',label:'Max Angle',kind:'number',placeholder:'16',step:'any'},{key:'scatter',label:'Scatter',kind:'number',placeholder:'3.6',step:'any'},{key:'desc',label:'Description',kind:'textarea',full:true,placeholder:'Describe this cannon'}];if(type==='attachment')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. Reinforced Barrel'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. reinforced_barrel',hint:'Lowercase, underscores ok'},{key:'slotType',label:'Slot Type',kind:'select',options:['sail','general']},{key:'dmgBonus',label:'Damage Bonus',kind:'number',placeholder:'0.10',step:'any',hint:'Decimal: 0.15 = +15%'},{key:'rateBonus',label:'Rate Bonus',kind:'number',placeholder:'0.00',step:'any',hint:'Decimal: 0.10 = +10%'},{key:'desc',label:'Description',kind:'textarea',full:true,placeholder:'Describe this attachment'}];if(type==='cosmetic')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. Golden Lantern'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. golden_lantern',hint:'Lowercase, underscores ok'},{key:'slotType',label:'Slot Type',kind:'select',options:['lantern']},{key:'dmgBonus',label:'Damage Bonus',kind:'number',placeholder:'0.10',step:'any'},{key:'rateBonus',label:'Rate Bonus',kind:'number',placeholder:'0.05',step:'any'},{key:'desc',label:'Description',kind:'textarea',full:true,placeholder:'Describe this cosmetic'}];if(type==='ammo')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. Round Shots'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. round',hint:'Lowercase, no spaces'},{key:'hullPct',label:'Hull Damage %',kind:'number',placeholder:'100'},{key:'sailsRating',label:'Sails Rating',kind:'number',placeholder:'1'},{key:'crewRating',label:'Crew Rating',kind:'number',placeholder:'1'},{key:'weight',label:'Weight',kind:'number',placeholder:'1'},{key:'special',label:'Special Effect',kind:'select',options:['','fire','pierce','slow'],hint:'Optional'},{key:'rangeModPct',label:'Range Modifier %',kind:'number',placeholder:'0',step:'any',hint:'e.g. -40 for -40% range. 0 for none'},{key:'desc',label:'Description',kind:'textarea',full:true,placeholder:'Describe this ammo'}];if(type==='crew')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. Powder Monkey'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. powder_monkey',hint:'Lowercase, underscores ok'},{key:'faction',label:'Faction',kind:'select',options:['Pirates','Sailors','Military','Adventurers']},{key:'types',label:'Types',kind:'text',placeholder:'e.g. Combat, Boarding',hint:'Comma-separated tags'},{key:'dmgBonus',label:'Damage Bonus',kind:'number',placeholder:'0.12',step:'any',hint:'Decimal: 0.12 = +12%'},{key:'reloadBonus',label:'Reload Bonus',kind:'number',placeholder:'0.25',step:'any',hint:'Decimal: 0.25 = +25%'},{key:'speedBonus',label:'Speed Bonus',kind:'number',placeholder:'0.10',step:'any',hint:'Decimal: 0.10 = +10%'},{key:'maneuverBonus',label:'Maneuver Bonus',kind:'number',placeholder:'0.10',step:'any',hint:'Decimal: 0.10 = +10%'},{key:'bonus',label:'Bonus Description',kind:'textarea',full:true,placeholder:'Describe this crew bonus'}];if(type==='supportitem')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. Black Double Powder'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. black_double_powder',hint:'Lowercase, underscores ok'},{key:'group',label:'Group',kind:'select',options:['Repair & Durability','Ship Enhancements','Special Powders & Ammunition','Crew Items','Group Support Items']},{key:'types',label:'Types',kind:'text',placeholder:'e.g. Damage, Reload',hint:'Comma-separated tags'},{key:'dmgBonus',label:'Damage Bonus',kind:'number',placeholder:'0.08',step:'any',hint:'Decimal: 0.08 = +8%'},{key:'reloadBonus',label:'Reload Bonus',kind:'number',placeholder:'0.05',step:'any',hint:'Decimal: 0.05 = +5%'},{key:'speedBonus',label:'Speed Bonus',kind:'number',placeholder:'0.05',step:'any',hint:'Decimal: 0.05 = +5%'},{key:'maneuverBonus',label:'Maneuver Bonus',kind:'number',placeholder:'0.02',step:'any',hint:'Decimal: 0.02 = +2%'},{key:'bonus',label:'Bonus Description',kind:'textarea',full:true,placeholder:'Describe this support bonus'}];if(type==='armourtype')return [{key:'name',label:'Name',kind:'text',placeholder:'e.g. Reinforced Oak'},{key:'id',label:'Unique ID',kind:'text',placeholder:'e.g. oak',hint:'Lowercase, no spaces'},{key:'value',label:'Armour Rating',kind:'number',placeholder:'25',hint:'Each point = −1 damage per shot'}];return [];}
function renderEditField(field,value){const safeValue=value==null?'':(Array.isArray(value)?value.join(', '):value);const fieldClass=field.full?'edit-field full':'edit-field';const hint=field.hint||'';if(field.kind==='textarea'){return `<div class="${fieldClass}"><div class="edit-label">${esc(field.label)}</div><textarea data-field="${esc(field.key)}" data-kind="textarea" placeholder="${esc(field.placeholder||'')}">${esc(safeValue)}</textarea><div class="edit-hint">${esc(hint)}</div></div>`;}if(field.kind==='select'){const options=(field.options||[]).map(opt=>{const label=opt===''?'None':opt;const selected=String(opt)===String(safeValue)?' selected':'';return `<option value="${esc(opt)}"${selected}>${esc(label)}</option>`;}).join('');return `<div class="${fieldClass}"><div class="edit-label">${esc(field.label)}</div><div class="edit-select-wrap"><select data-field="${esc(field.key)}" data-kind="select">${options}</select></div><div class="edit-hint">${esc(hint)}</div></div>`;}const inputType=field.kind==='number'?'number':'text';const stepAttr=field.kind==='number'?(field.step?` step="${esc(field.step)}"`:' step="1"'):'';const nullableAttr=field.nullable?' data-nullable="1"':'';return `<div class="${fieldClass}"><div class="edit-label">${esc(field.label)}</div><input type="${inputType}" data-field="${esc(field.key)}" data-kind="${esc(field.kind)}"${stepAttr}${nullableAttr} value="${esc(safeValue)}" placeholder="${esc(field.placeholder||'')}"><div class="edit-hint">${esc(hint)}</div></div>`;}
function openAddModal(type){openEditModal(type,-1);}function openEditModal(type,index){const arr=getArrayForType(type);if(!arr)return;editCtx={type,index};const item=index>-1?JSON.parse(JSON.stringify(arr[index])):templateForType(type);const defs=getFieldDefs(type);const labelMap={ship:'Ship',cannon:'Cannon',attachment:'Attachment',cosmetic:'Cosmetic',ammo:'Ammo Type',crew:'Crew Member',supportitem:'Support Item',armourtype:'Armour Type'};byId('edit-modal-title').textContent=(index>-1?'Edit ':'Add New ')+labelMap[type];let html='<div class="edit-grid">';for(const def of defs)html+=renderEditField(def,item[def.key]);html+='</div>';byId('edit-modal-body').innerHTML=html;byId('edit-overlay').classList.add('open');}
function closeEditModal(){byId('edit-overlay').classList.remove('open');editCtx=null;}
function saveEdit(){if(!editCtx)return;const arr=getArrayForType(editCtx.type);if(!arr)return;const defs=getFieldDefs(editCtx.type);const entry=editCtx.index>-1?JSON.parse(JSON.stringify(arr[editCtx.index])):templateForType(editCtx.type);for(const field of defs){const el=byId('edit-overlay').querySelector(`[data-field="${field.key}"]`);if(!el)continue;if(field.kind==='number'){const raw=el.value.trim();if(raw==='')entry[field.key]=field.nullable?null:0;else{const parsed=Number(raw);if(Number.isNaN(parsed)){showToast('Invalid value for '+field.label,true);return;}entry[field.key]=parsed;}}else entry[field.key]=field.kind==='textarea'?el.value:el.value.trim();}if(editCtx.type==='crew'||editCtx.type==='supportitem')entry.types=String(entry.types||'').split(',').map(v=>v.trim()).filter(Boolean);if(editCtx.type==='attachment'||editCtx.type==='cosmetic'||editCtx.type==='ammo'||editCtx.type==='supportitem')delete entry.icon;if(!entry.id||!entry.name){showToast('Item needs both id and name',true);return;}entry.id=String(entry.id).toLowerCase().split(' ').join('_');for(let i=0;i<arr.length;i+=1){if(arr[i].id===entry.id&&i!==editCtx.index){showToast('That id already exists',true);return;}}if(editCtx.type==='crew'&&isBuiltInCrewId(entry.id)){ensureMetaShape(DATA);DATA.__meta.deletedDefaultCrewIds=DATA.__meta.deletedDefaultCrewIds.filter(id=>id!==entry.id);}if(editCtx.index>-1)arr[editCtx.index]=entry;else arr.push(entry);saveData();closeEditModal();refreshFromData();showToast('Saved',false);}
function openDeleteConfirm(type,index,name){deleteCtx={type,index};byId('del-confirm-text').textContent='Delete "'+name+'"? This cannot be undone.';byId('del-confirm').classList.add('show');}
function cancelDelete(){deleteCtx=null;byId('del-confirm').classList.remove('show');}
function confirmDelete(){if(!deleteCtx)return;const arr=getArrayForType(deleteCtx.type);if(!arr)return;const removed=arr.splice(deleteCtx.index,1)[0];if(removed&&removed.id){if(deleteCtx.type==='crew'&&isBuiltInCrewId(removed.id)){ensureMetaShape(DATA);if(!DATA.__meta.deletedDefaultCrewIds.includes(removed.id))DATA.__meta.deletedDefaultCrewIds.push(removed.id);}if(selectedAmmo===removed.id&&DATA.ammo[0])selectedAmmo=DATA.ammo[0].id;for(let i=selectedCrew.length-1;i>=0;i-=1){if(selectedCrew[i]===removed.id)selectedCrew.splice(i,1);}for(let i=selectedSupportItems.length-1;i>=0;i-=1){if(selectedSupportItems[i]===removed.id)selectedSupportItems.splice(i,1);}}saveData();cancelDelete();refreshFromData();showToast('Deleted',false);}
function changePassword(){const oldPw=byId('pw-old').value;const newPw=byId('pw-new').value;const msg=byId('pw-save-msg');if(oldPw!==DATA.password){msg.style.color='var(--red-light)';msg.textContent='Current password incorrect.';return;}if(!newPw||newPw.length<4){msg.style.color='var(--red-light)';msg.textContent='New password must be at least 4 characters.';return;}DATA.password=newPw;saveData();byId('pw-old').value='';byId('pw-new').value='';msg.style.color='var(--teal-light)';msg.textContent='Password updated.';setTimeout(()=>{msg.textContent='';},2200);}
function exportData(){const blob=new Blob([JSON.stringify(DATA,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const link=document.createElement('a');link.href=url;link.download='wsb_data.json';link.click();URL.revokeObjectURL(url);showToast('Exported JSON backup',false);}
function importData(input){const file=input.files[0];if(!file)return;const reader=new FileReader();reader.onload=function(e){try{DATA=JSON.parse(e.target.result);if(!DATA.password)DATA.password='admiral';if(!Array.isArray(DATA.armourTypes))DATA.armourTypes=JSON.parse(JSON.stringify(DEFAULT_DATA.armourTypes));if(!Array.isArray(DATA.supportItems))DATA.supportItems=JSON.parse(JSON.stringify(DEFAULT_DATA.supportItems));syncBuiltInCannons(DATA);syncAttachmentCatalog(DATA);syncCosmeticCatalog(DATA);saveData();refreshFromData();showToast('Imported JSON backup',false);}catch(err){showToast('Import failed',true);}input.value='';};reader.readAsText(file);}
function resetToDefaults(){if(!confirm('Reset all calculator data to defaults?'))return;DATA=JSON.parse(JSON.stringify(DEFAULT_DATA));selectedCrew.length=0;selectedSupportItems.length=0;selectedAmmo='round';saveData();refreshFromData();showToast('Reset to defaults',false);}
function refreshFromData(){const currentShip=byId('ship-select')?byId('ship-select').value:'';const currentTarget=byId('target-ship-select')?byId('target-ship-select').value:'';for(let i=selectedSupportItems.length-1;i>=0;i-=1){if(!findById(DATA.supportItems,selectedSupportItems[i]))selectedSupportItems.splice(i,1);}if(attachmentSelections.sail&&!DATA.attachments.some(item=>item.id===attachmentSelections.sail&&(item.slotType||'general')==='sail'))attachmentSelections.sail='';attachmentSelections.general=attachmentSelections.general.map(id=>DATA.attachments.some(item=>item.id===id&&(item.slotType||'general')!=='sail')?id:'');if(cosmeticSelections.lantern&&!DATA.cosmetics.some(item=>item.id===cosmeticSelections.lantern&&(item.slotType||'lantern')==='lantern'))cosmeticSelections.lantern='';buildShipSelects();if(currentShip&&findShip(currentShip))byId('ship-select').value=currentShip;if(currentTarget&&findShip(currentTarget))byId('target-ship-select').value=currentTarget;buildAmmo();buildAttachments();buildCosmetics();buildCrew();buildSupportItems();applyAmmoCollapsedState();applyAttachmentsCollapsedState();applyCosmeticsCollapsedState();applyCrewCollapsedState();applySupportCollapsedState();buildAdminTables();onShipChange();onTargetShipChange();}
function runSelfTests(){function assert(cond,msg){if(!cond&&typeof console!=='undefined'&&typeof console.warn==='function')console.warn('Test failed: '+msg);}assert(typeof esc==='function','esc helper should exist');assert(esc('<a&b>')==='&lt;a&amp;b&gt;','esc should HTML-escape');assert(rateToRoman(4)==='IV','roman conversion should work');assert(findCannon('none')!==null,'default cannon should exist');assert(typeof calculate==='function','calculate should exist');assert(Number(getComputedStyle(byId('edit-overlay')).zIndex)>=1000,'edit overlay should sit above admin overlay');assert(rankAllowsShip('VII-VI',7)===true,'rate VII cannon should allow rate 7');assert(rankAllowsShip('VII-VI',5)===true,'higher-tier ships should be able to equip lower-rate cannons');assert(rankAllowsShip('IV-III',1)===true,'rate I ship should be able to equip IV-III cannons');assert(rankAllowsShip('II',3)===false,'rate III ship should not equip rate II-only cannons');assert(getCannonsForPosition(1,true).every(c=>!String(c.category).includes('Bombard')&&c.category!=='Special'),'broadside should exclude bombards and specials');assert(getCannonsForPosition(1,false,true).every(c=>c.category!=='Special'),'stern should exclude special weapons');assert(!byId('attachments-grid').textContent.includes('🔩'),'attachment emoji icons should not render');assert(!!byId('ammo-toggle-btn'),'ammo toggle button should exist');assert(!!byId('attachments-toggle-btn'),'attachments toggle button should exist');assert(!!byId('cosmetics-toggle-btn'),'cosmetics toggle button should exist');assert(!!byId('crew-toggle-btn'),'crew toggle button should exist');assert(!!byId('support-grid'),'support grid should exist');assert(!!byId('support-toggle-btn'),'support toggle button should exist');assert(byId('ship-select').querySelectorAll('optgroup').length>0,'ship dropdown should be grouped into optgroups');assert([...byId('ship-select').querySelectorAll('optgroup')].some(group=>group.label.includes('Rate')&&group.label.includes('Imperial')),'ship dropdown should include grouped rate/type labels');assert(!!byId('report-meta'),'report meta section should exist');assert(!!byId('results-hero-badge'),'results hero badge should exist');assert(!!byId('attach-sail-select'),'sail attachment slot should exist');assert(document.querySelectorAll('.js-general-attach-select').length===5,'five general attachment slots should exist');assert(!!byId('cosmetic-lantern-select'),'lantern cosmetic slot should exist');assert(Array.isArray(DATA.supportItems),'support items should exist');}
function init(){buildShipSelects();buildAmmo();buildAttachments();buildCosmetics();buildCrew();buildSupportItems();applyAmmoCollapsedState();applyAttachmentsCollapsedState();applyCosmeticsCollapsedState();applyCrewCollapsedState();applySupportCollapsedState();buildAdminTables();byId('ship-select').value='black_prince';byId('target-ship-select').value='huracan';runSelfTests();onShipChange();onTargetShipChange();}
init();
